#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100

// Structure to represent a warrior
typedef struct {
    int power;
    int level;
} Warrior;

// Comparison function for sorting warriors based on level and power
int compareWarriors(const void *a, const void *b) {
    Warrior *w1 = (Warrior *)a;
    Warrior *w2 = (Warrior *)b;
    if (w1->level != w2->level) {
        return w1->level - w2->level;
    } else {
        return w2->power - w1->power;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Warrior soints[N], sofloats[M];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &soints[i].power, &soints[i].level);
        }
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &sofloats[i].power, &sofloats[i].level);
        }
        qsort(soints, N, sizeof(Warrior), compareWarriors);
        qsort(sofloats, M, sizeof(Warrior), compareWarriors);
        int minChakra = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (soints[i].level == sofloats[j].level) {
                    if (soints[i].power <= sofloats[j].power) {
                        minChakra += sofloats[j].power - soints[i].power + 1;
                    }
                    break;
                }
            }
        }
        printf("%d\n", minChakra);
    }
    return 0;
}

