import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            Warrior[] soints = new Warrior[N];
            Warrior[] sofloats = new Warrior[M];
            for (int i = 0; i < N; i++) {
                soints[i] = new Warrior(sc.nextInt(), sc.nextInt());
            }
            for (int i = 0; i < M; i++) {
                sofloats[i] = new Warrior(sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(soints);
            Arrays.sort(sofloats);
            int minChakra = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if (soints[i].level == sofloats[j].level) {
                        if (soints[i].power <= sofloats[j].power) {
                            minChakra += sofloats[j].power - soints[i].power + 1;
                        }
                        break;
                    }
                }
            }
            System.out.println(minChakra);
        }
    }
}

class Warrior implements Comparable<Warrior> {
    int power;
    int level;
    Warrior(int power, int level) {
        this.power = power;
        this.level = level;
    }
    @Override
    public int compareTo(Warrior w) {
        if (this.level != w.level) {
            return this.level - w.level;
        } else {
            return w.power - this.power;
        }
    }
}

